import { ref, onMounted } from 'vue'
import profile from '@/api/profile'
import { ElMessage } from 'element-plus'

export function useModules() {
  const loading = ref(false)
  const modules = ref([])

  const fetchModulesData = async () => {
    loading.value = true
    try {
      const response = await profile.getData()
      if (response.data?.code === 200) {
        modules.value = [
          { type: 'basic_info', data: response.data.data.basic_info },
          { type: 'job_intention', data: response.data.data.job_intention },
          { type: 'work_experience', data: response.data.data.work_experience },
          { type: 'education', data: response.data.data.education },
          { type: 'project', data: response.data.data.project },
          { type: 'skill', data: response.data.data.skill },
          { type: 'certificate', data: response.data.data.certificate },
          { type: 'language', data: response.data.data.language },
          { type: 'portfolio', data: response.data.data.portfolio },
          { type: 'social_link', data: response.data.data.social_link }
        ]
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      ElMessage.error('获取模块数据失败')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    modules,
    fetchModulesData
  }
}
